import { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom";
import { 
  ChevronDown, ChevronRight, LayoutGrid, BookOpen, 
  GraduationCap, CheckCircle2, ShieldCheck, RefreshCw
} from "lucide-react";
import axios from "../api/axios";
import toast from "react-hot-toast";

const Sidebar = () => {
  const location = useLocation();
  const [menuData, setMenuData] = useState([]);
  const [loading, setLoading] = useState(true);

  // Toggle States
  const [adminOpen, setAdminOpen] = useState(true);
  const [examsListOpen, setExamsListOpen] = useState(true);
  
  // Dynamic Toggles using IDs
  const [openExams, setOpenExams] = useState({});
  const [openCategories, setOpenCategories] = useState({});

  const fetchData = async () => {
    setLoading(true);
    try {
      const res = await axios.get("/public/sidebar-menu");
      if (res.data.success) {
        setMenuData(res.data.data);
      }
    } catch (err) {
      console.error("Sidebar Data Error:", err);
      toast.error("SIDEBAR SYNC FAILED");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const toggleExam = (id) => {
    setOpenExams(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const toggleCategory = (id) => {
    setOpenCategories(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const isActive = (path) => location.pathname === path;

  return (
    <div className="w-64 h-screen bg-[#0F172A] text-white flex flex-col border-r border-slate-800 shadow-2xl overflow-hidden">
      
      {/* --- LOGO SECTION --- */}
      <div className="p-6 border-b border-slate-800 flex justify-between items-center">
        <h2 className="text-xl font-black uppercase tracking-tighter text-blue-500">
          MEDHASHALA
        </h2>
        <button onClick={fetchData} className="text-slate-500 hover:text-white transition-colors">
          <RefreshCw size={14} className={loading ? "animate-spin" : ""} />
        </button>
      </div>

      <div className="flex-1 p-4 overflow-y-auto space-y-6 custom-scrollbar">
        
        {/* --- DYNAMIC EXAMS LIST (LEVEL 1) --- */}
        <div>
          <button
            onClick={() => setExamsListOpen(!examsListOpen)}
            className="flex justify-between items-center w-full py-2 mb-2 font-black uppercase text-[10px] tracking-widest text-slate-500 hover:text-white transition-all"
          >
            <span>Exams List</span>
            {examsListOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </button>

          {examsListOpen && (
            <div className="space-y-1">
              {loading && menuData.length === 0 ? (
                <div className="p-2 text-[10px] font-black text-slate-600 animate-pulse uppercase tracking-widest">Loading Exams...</div>
              ) : menuData.map((exam) => (
                <div key={exam._id} className="space-y-1">
                  
                  {/* EXAM NAME BUTTON */}
                  <button
                    onClick={() => toggleExam(exam._id)}
                    className={`flex items-center justify-between w-full p-2.5 text-xs font-bold rounded-xl transition-all ${
                      openExams[exam._id] ? "bg-blue-600/10 text-blue-400" : "text-slate-300 hover:bg-slate-800/50"
                    }`}
                  >
                    <div className="flex items-center gap-3">
                      <GraduationCap size={16} />
                      <span className="uppercase tracking-tight">{exam.examName}</span>
                    </div>
                    {openExams[exam._id] ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                  </button>

                  {/* --- CATEGORIES LIST (LEVEL 2) --- */}
                  {openExams[exam._id] && (
                    <div className="ml-5 border-l-2 border-slate-800 pl-3 py-1 space-y-1">
                      {exam.categories?.length > 0 ? (
                        exam.categories.map((cat) => (
                          <div key={cat._id}>
                            <button
                              onClick={() => toggleCategory(cat._id)}
                              className={`flex items-center justify-between w-full p-2 text-[11px] font-bold transition-all ${
                                openCategories[cat._id] ? "text-emerald-400" : "text-slate-500 hover:text-white"
                              }`}
                            >
                              <span>{cat.catName}</span>
                              {openCategories[cat._id] ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                            </button>

                            {/* --- FEATURES LIST (LEVEL 3) --- */}
                            {openCategories[cat._id] && (
                              <div className="ml-2 mt-1 space-y-1 bg-slate-800/20 rounded-lg p-2">
                                {cat.features?.map((feat) => (
                                  <div key={feat} className="flex items-center gap-2 py-1 px-2 text-[9px] font-black text-slate-400 hover:text-blue-400 cursor-pointer uppercase transition-colors">
                                    <CheckCircle2 size={10} className="text-emerald-500" />
                                    {feat}
                                  </div>
                                ))}
                              </div>
                            )}
                          </div>
                        ))
                      ) : (
                        <div className="text-[9px] p-2 text-slate-600 uppercase italic">No Categories</div>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>

        <hr className="border-slate-800/50 mx-2" />

        {/* --- ADMIN CONTROLLER SECTION --- */}
        <div>
          <button
            onClick={() => setAdminOpen(!adminOpen)}
            className="flex justify-between items-center w-full py-2 px-2 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 hover:text-white transition-colors"
          >
            <span>Admin Controller</span>
            {adminOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </button>

          {adminOpen && (
            <div className="mt-2 space-y-1">
              <Link
                to="/dashboard/exam-master"
                className={`flex items-center gap-3 p-2.5 rounded-xl text-xs font-bold transition-all ${
                  isActive("/dashboard/exam-master") 
                    ? "bg-blue-600 text-white shadow-lg shadow-blue-900/50" 
                    : "text-slate-400 hover:bg-slate-800 hover:text-white"
                }`}
              >
                <BookOpen size={16} /> Exam Master
              </Link>

              <Link
                to="/dashboard/category-master"
                className={`flex items-center gap-3 p-2.5 rounded-xl text-xs font-bold transition-all ${
                  isActive("/dashboard/category-master") 
                    ? "bg-emerald-600 text-white shadow-lg shadow-emerald-900/50" 
                    : "text-slate-400 hover:bg-slate-800 hover:text-white"
                }`}
              >
                <LayoutGrid size={16} /> Category Master
              </Link>
            </div>
          )}
        </div>
      </div>

      {/* --- SIDEBAR FOOTER --- */}
      <div className="p-4 bg-slate-950/50 border-t border-slate-800 flex items-center justify-center gap-2">
         <ShieldCheck size={12} className="text-slate-600" />
         <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Admin Access Only</span>
      </div>
    </div>
  );
};

export default Sidebar;
